import{_ as t,o as a,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"58. Community Mental Health Engagement Worker","description":"","frontmatter":{"title":"58. Community Mental Health Engagement Worker","eba":"Mental Health Services 2024-2028","topics":["preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/staffing/58-community-mental-health-engagement-worker.md","filePath":"ebas/mental-health/common-terms/staffing/58-community-mental-health-engagement-worker.md"}'),o={name:"ebas/mental-health/common-terms/staffing/58-community-mental-health-engagement-worker.md"};function s(i,e,l,m,c,p){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_58-community-mental-health-engagement-worker" tabindex="-1">58. Community Mental Health Engagement Worker <a class="header-anchor" href="#_58-community-mental-health-engagement-worker" aria-label="Permalink to &quot;58. Community Mental Health Engagement Worker&quot;">​</a></h1><p><strong>58.1</strong> Newly graduated health practitioners who are nurses (Registered and Enrolled), social workers and occupational therapists may be employed as ‘Community mental health engagement workers’ in community-based services.</p><p><strong>58.2</strong> The role will also provide a pathway into mental health for newly registered health practitioners.</p><p><strong>58.3</strong> Purpose of the role</p><p><strong>(a)</strong> The role will help improve consumer outcomes by:</p><p><strong>(i)</strong> assisting consumers and their families and carers to navigate mental health services</p><p><strong>(ii)</strong> provide information to enable improved access to other services (such as general practice, other health specialists and associated clinical services, consumer or carer peer support, carer respite, the NDIS and other social welfare agencies) and</p><p><strong>(iii)</strong> freeing up clinicians to focus on their therapeutic work</p><p><strong>(iv)</strong> other duties as directed by health service within scope of qualification and role classifications.</p><p><strong>58.4</strong> The role will work under direct supervision from a health practitioner and not be allocated a caseload.</p><p><strong>58.5</strong> The role will be fixed term for a maximum of 18 months.</p><p><strong>58.6</strong> Classification</p><p><strong>(a)</strong> The commencing classification for each eligible discipline will be as follows:</p><p><strong>(i)</strong> PEN Level 1 Year 7</p><p><strong>(ii)</strong> OT Grade 1</p><p><strong>(iii)</strong> RPN Grade 2 Year 1</p><p><strong>(iv)</strong> SW Grade 1 Year 1</p>',17)])])}const d=t(o,[["render",s]]);export{h as __pageData,d as default};
